const input = $('Execute Sub-workflow Trigger').first().json || {};
const cityQuery = String(input.city_query || '').trim();
const districtQuery = String(input.district_query || '').trim();

if ($json.error) {
  return [
    {
      json: {
        ok: false,
        error_code: 'NHANH_DEPOT_API_ERROR',
        message: String($json.error),
        city_query: cityQuery,
        district_query: districtQuery,
        matched_depot_ids: [],
        matched_total: 0,
        items: [],
      },
    },
  ];
}

const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/tp\.?/g, '')
  .replace(/thanh pho/g, '')
  .replace(/\s+/g, ' ')
  .trim();

const cityNeedle = normalize(cityQuery);
const districtNeedle = normalize(districtQuery);
const root = $json?.data ?? $json?.result ?? $json ?? {};
const rawItems = Array.isArray(root?.data)
  ? root.data
  : Array.isArray(root)
    ? root
    : [];

const items = rawItems
  .map((item) => {
    const location = item.location ?? {};
    const cityName = String(location.cityName || '').trim();
    const districtName = String(location.districtName || '').trim();
    const cityNorm = normalize(cityName);
    const districtNorm = normalize(districtName);

    let matchScore = 0;
    if (cityNeedle && cityNorm.includes(cityNeedle)) matchScore += 1;
    if (districtNeedle && districtNorm.includes(districtNeedle)) matchScore += 2;

    return {
      id: item.id ?? null,
      code: item.code ?? '',
      name: item.name ?? '',
      city_name: cityName,
      district_name: districtName,
      ward_name: String(location.wardName || '').trim(),
      address: String(location.address || '').trim(),
      match_score: matchScore,
    };
  })
  .sort((a, b) => {
    if (b.match_score !== a.match_score) return b.match_score - a.match_score;
    return a.name.localeCompare(b.name, 'vi');
  });

const matchedItems = items.filter((item) => item.match_score > 0);
const finalItems = matchedItems.length > 0 ? matchedItems : [];

return [
  {
    json: {
      ok: true,
      city_query: cityQuery,
      district_query: districtQuery,
      matched_total: finalItems.length,
      matched_depot_ids: finalItems.map((item) => item.id).filter((value) => value !== null),
      items: finalItems,
    },
  },
];

const input = $('Execute Sub-workflow Trigger').first().json || {};
const depotResult = $('Code Match Depots By Location').first().json || {};

const productQuery = String(input.product_query || '').trim();
const cityQuery = String(input.city_query || '').trim();
const districtQuery = String(input.district_query || '').trim();
const maxResults = Math.max(1, Math.min(20, Number(input.max_results || 5)));
const depotIds = Array.isArray(depotResult.matched_depot_ids) ? depotResult.matched_depot_ids : [];

const filters = {};
if (productQuery) filters.name = productQuery;
if (depotIds.length > 0) filters.depotIds = depotIds;

return [
  {
    json: {
      product_query: productQuery,
      customer_city: cityQuery,
      customer_district: districtQuery,
      applied_depot_ids: depotIds,
      request_body: {
        filters,
        paginator: {
          size: maxResults
        },
        dataOptions: {}
      }
    }
  }
];

const triggerInput = $('Execute Sub-workflow Trigger').first().json || {};
const requestContext = $('Code Build Inventory Request').first().json || {};
const depotContext = $('Code Match Depots By Location').first().json || {};

const productQuery = String(triggerInput.product_query || '').trim();
const customerCity = String(triggerInput.city_query || '').trim();
const customerDistrict = String(triggerInput.district_query || '').trim();
const appliedDepotIds = Array.isArray(requestContext.applied_depot_ids) ? requestContext.applied_depot_ids : [];

if ($json.error) {
  return [
    {
      json: {
        ok: false,
        error_code: 'NHANH_API_ERROR',
        message: String($json.error),
        product_query: productQuery,
        customer_city: customerCity,
        customer_district: customerDistrict,
        applied_depot_ids: appliedDepotIds,
        matched_total: Number(depotContext.matched_total || 0),
        total: 0,
        available_count: 0,
        available_items: [],
        items: []
      }
    }
  ];
}

const root = $json?.data ?? $json?.result ?? $json ?? {};
const rawItems = Array.isArray(root?.products)
  ? root.products
  : Array.isArray(root?.data)
    ? root.data
    : Array.isArray(root)
      ? root
      : [];

const items = rawItems
  .map((item) => {
    const inventory = item.inventory ?? {};
    return {
      id: item.id ?? item.productId ?? null,
      code: item.code ?? item.productCode ?? '',
      name: item.name ?? '',
      barcode: item.barcode ?? '',
      price: Number(item?.prices?.price ?? 0),
      remain: Number(inventory.remain ?? item.remain ?? 0),
      available: Number(inventory.available ?? item.available ?? 0),
      shipping: Number(inventory.shipping ?? item.shipping ?? 0),
      holding: Number(inventory.holding ?? item.holding ?? 0),
      damaged: Number(inventory.damaged ?? item.damaged ?? item.damage ?? 0),
      depots: inventory.depots ?? item.depots ?? [],
      has_stock: Number(inventory.available ?? item.available ?? 0) > 0
    };
  })
  .sort((a, b) => {
    if (b.available !== a.available) return b.available - a.available;
    if (b.remain !== a.remain) return b.remain - a.remain;
    return a.name.localeCompare(b.name, 'vi');
  });

const availableItems = items.filter((item) => item.available > 0);

return [
  {
    json: {
      ok: true,
      product_query: productQuery,
      customer_city: customerCity,
      customer_district: customerDistrict,
      matched_total: Number(depotContext.matched_total || 0),
      matched_depot_ids: Array.isArray(depotContext.matched_depot_ids) ? depotContext.matched_depot_ids : [],
      applied_depot_ids: appliedDepotIds,
      total: items.length,
      available_count: availableItems.length,
      available_items: availableItems,
      items
    }
  }
];

